Modified greedy insertion with incremental cost comparison and fallback to new assign if no improving slot found, while preserving feasibility via trial-and-commit.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := 0; shipIdx < len(oris); shipIdx++ {
		bestDelta := math.MaxFloat64
		bestAssignIdx := -1
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx

		originalCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			originalCosts[i] = dispatch.Assigns[i].Cost
		}

		for tryAssignIdx := 0; tryAssignIdx <= dispatch.AssignsLen; tryAssignIdx++ {
			assignPtr := &dispatch.Assigns[tryAssignIdx]

			savedState := assignPtr.Cost
			success := false
			candidateDelta := 0.0

			if tryAssignIdx == dispatch.AssignsLen {
				tmpAssign := &dispatch.Assigns[tryAssignIdx]
				oldLen := tmpAssign.StationsLen
				oldCost := tmpAssign.Cost
				ok := tmpAssign.AddShip(shipID, ori, des)
				if ok {
					tmpAssign.GenRoute()
					if tmpAssign.Cost >= 0 {
						success = true
						candidateDelta = tmpAssign.Cost - oldCost
					} else {
						tmpAssign.RemoveShip(shipID)
						tmpAssign.GenRoute()
					}
				}
				if !success {
					tmpAssign.StationsLen = oldLen
					tmpAssign.Cost = oldCost
				}
			} else {
				ok := assignPtr.AddShip(shipID, ori, des)
				if ok {
					assignPtr.GenRoute()
					if assignPtr.Cost >= 0 {
						success = true
						candidateDelta = assignPtr.Cost - savedState
					} else {
						assignPtr.RemoveShip(shipID)
						assignPtr.GenRoute()
					}
				}
				if !success {
					assignPtr.Cost = originalCosts[tryAssignIdx]
				}
			}

			if success && candidateDelta < bestDelta {
				bestDelta = candidateDelta
				bestAssignIdx = tryAssignIdx
			}

			if tryAssignIdx < dispatch.AssignsLen && !success && assignPtr.Cost != originalCosts[tryAssignIdx] {
				assignPtr.Cost = originalCosts[tryAssignIdx]
			}
		}

		for i := 0; i < dispatch.AssignsLen; i++ {
			dispatch.Assigns[i].Cost = originalCosts[i]
		}

		inserted := false
		if bestAssignIdx >= 0 && bestAssignIdx < dispatch.AssignsLen {
			if dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des) {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				inserted = true
			}
		}
		if !inserted {
			newIdx := dispatch.AssignsLen
			if newIdx < MAXASSIGNS {
				tmp := &dispatch.Assigns[newIdx]
				if tmp.AddShip(shipID, ori, des) {
					tmp.GenRoute()
					if tmp.Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						tmp.RemoveShip(shipID)
						tmp.GenRoute()
					}
				}
			}
		}
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			fallbackIdx := dispatch.AssignsLen
			tmp := &dispatch.Assigns[fallbackIdx]
			oldSLen := tmp.StationsLen
			oldCst := tmp.Cost
			if tmp.AddShip(shipID, ori, des) {
				tmp.GenRoute()
				if tmp.Cost >= 0 {
					dispatch.AssignsLen++
					inserted = true
				} else {
					tmp.RemoveShip(shipID)
					tmp.StationsLen = oldSLen
					tmp.Cost = oldCst
					tmp.GenRoute()
				}
			} else {
				tmp.StationsLen = oldSLen
				tmp.Cost = oldCst
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

